SELECT 
FROM sprints
WHERE project_id = #{projectId}
  AND status = #{status}
  AND tenant_id = #{tenantId}
ORDER BY start_date ASC
LIMIT 1

SELECT 
FROM sprints
WHERE project_id = #{projectId}
  AND status = #{status}
  AND tenant_id = #{tenantId}
ORDER BY end_date DESC
