SELECT 
FROM sprints
WHERE project_id = #{projectId}
  AND tenant_id = #{tenantId}
ORDER BY id DESC

SELECT COUNT(*)
FROM sprints
WHERE project_id = #{projectId}
  AND tenant_id = #{tenantId}

