UPDATE sprints
SET project_id = #{s.projectId},
    name       = #{s.name},
    length     = #{s.length},
    start_date = #{s.startDate},
    end_date   = #{s.endDate},
    status     = #{s.status}
WHERE id = #{s.id}
  AND tenant_id = #{tenantId}
